mapper.select:
SELECT C.ID AS id, C.CHECK_NO AS checkNo, C.WAREHOUSE_ID AS warehouseId, C.WAREHOUSE_NAME AS warehouseName, C.CHECK_DATE AS checkDate, C.CHECK_START_DATE AS checkStartDate, C.CHECK_END_DATE AS checkEndDate, C.CHECK_TITLE AS checkTitle, C.CHECK_TYPE AS checkType, CASE WHEN C.CHECK_TYPE = 1 THEN '全量盘点' WHEN C.CHECK_TYPE = 2 THEN '部分盘点' ELSE '未知' END AS checkTypeName, C.CHECK_STATUS AS checkStatus, CASE WHEN C.CHECK_STATUS = 0 THEN '待盘点' WHEN C.CHECK_STATUS = 1 THEN '盘点中' WHEN C.CHECK_STATUS = 2 THEN '已完成' ELSE '未知' END AS checkStatusName, C.CHECK_PERSON_ID AS checkPersonId, C.CHECK_PERSON_NAME AS checkPersonName, C.REMARK AS remark, C.CREATE_BY AS createBy, C.CREATE_BY_NAME AS createByName, C.CREATE_TIME AS createTime, C.UPDATE_BY AS updateBy, C.UPDATE_BY_NAME AS updateByName, C.UPDATE_TIME AS updateTime, NVL((SELECT COUNT(*) FROM E_MATERIAL_STOCK_CHECK_DETAIL WHERE CHECK_ID = C.ID), 0) AS totalDetailCount, NVL((SELECT COUNT(*) FROM E_MATERIAL_STOCK_CHECK_DETAIL WHERE CHECK_ID = C.ID AND (CHECK_STATUS IS NULL OR CHECK_STATUS = 0)), 0) AS uncheckedCount, NVL((SELECT COUNT(*) FROM E_MATERIAL_STOCK_CHECK_DETAIL WHERE CHECK_ID = C.ID AND CHECK_STATUS = 1), 0) AS pendingConfirmCount, NVL((SELECT COUNT(*) FROM E_MATERIAL_STOCK_CHECK_DETAIL WHERE CHECK_ID = C.ID AND CHECK_STATUS = 2), 0) AS checkedCount FROM E_MATERIAL_STOCK_CHECK C
C.DEL_FLAG = 0
AND C.CHECK_NO LIKE #{checkNoPattern}
AND C.WAREHOUSE_ID = #{warehouseId}
AND C.WAREHOUSE_NAME LIKE #{warehouseNamePattern}
AND C.CHECK_DATE >= #{checkDateStart}
AND C.CHECK_DATE <= #{checkDateEnd}
AND C.CHECK_STATUS = #{checkStatus}
AND C.CHECK_PERSON_NAME LIKE #{checkPersonNamePattern}
AND C.CHECK_TITLE LIKE #{checkTitlePattern}
ORDER BY C.CREATE_TIME DESC

SELECT COUNT(*)
FROM E_MATERIAL_STOCK_CHECK
WHERE CHECK_NO = #{checkNo}
AND DEL_FLAG = 0

    AND ID != #{id}

SELECT -- 盘点明细表字段 CD.ID AS id, CD.CHECK_ID AS checkId, CD.MATERIAL_ID AS materialId, CD.MATERIAL_NAME AS materialName, CD.SPECIFICATION_MODEL AS specificationModel, CD.UNIT_CODE AS unitCode, CD.UNIT_NAME AS unitName, CD.BOOK_QUANTITY AS bookQuantity, CD.CHECK_QUANTITY AS checkQuantity, CD.DIFFERENCE_QUANTITY AS differenceQuantity, CD.DIFFERENCE_TYPE AS differenceType, CASE WHEN CD.DIFFERENCE_TYPE = 1 THEN '盘盈' WHEN CD.DIFFERENCE_TYPE = 2 THEN '盘亏' WHEN CD.DIFFERENCE_TYPE = 0 THEN '无差异' ELSE '未知' END AS differenceTypeName, CD.WAREHOUSE_IN_DETAIL_ID AS warehouseInDetailId, CD.CHECK_STATUS AS checkStatus, CASE WHEN CD.CHECK_STATUS = 0 THEN '待盘点' WHEN CD.CHECK_STATUS = 1 THEN '已盘点' ELSE '未知' END AS checkStatusName, CD.REMARK AS remark, CD.AUDIT_BY AS auditBy, CD.AUDIT_BY_NAME AS auditByName, CD.AUDIT_TIME AS auditTime, -- 入库明细表字段 WID.WAREHOUSE_IN_ID AS warehouseInId, WID.WAREHOUSE_IN_QUANTITY AS warehouseInQuantity, WID.OUT_QUANTITY AS outQuantity, WID.REMAINING_QUANTITY AS remainingQuantity, WID.TAX_INCLUDED_UNIT_PRICE AS taxIncludedUnitPrice, WID.TAX_INCLUDED_AMOUNT AS taxIncludedAmount, WID.SUPPLIER_ID AS supplierId, WID.SUPPLIER_NAME AS supplierName, WID.BRAND AS brand, WID.SPECIFICATION_DESC AS specificationDesc, -- 入库主表字段 WI.WAREHOUSE_IN_NO AS warehouseInNo, WI.WAREHOUSE_IN_TITLE AS warehouseInTitle, WI.WAREHOUSE_IN_TYPE_CODE AS warehouseInTypeCode, WI.WAREHOUSE_IN_TYPE_NAME AS warehouseInTypeName, WI.WAREHOUSE_IN_DATE AS warehouseInDate, WI.DEPT_ID AS deptId, WI.DEPT_NAME AS deptName, WI.ACCEPTANCE_STATUS AS acceptanceStatus, CASE WHEN WI.ACCEPTANCE_STATUS = 0 THEN '待验收' WHEN WI.ACCEPTANCE_STATUS = 1 THEN '通过' WHEN WI.ACCEPTANCE_STATUS = 2 THEN '不通过' ELSE '未知' END AS acceptanceStatusName, WI.ACCEPTANCE_REMARKS AS acceptanceRemarks FROM E_MATERIAL_STOCK_CHECK_DETAIL CD LEFT JOIN E_MATERIAL_WAREHOUSE_IN_DETAIL WID ON CD.WAREHOUSE_IN_DETAIL_ID = WID.ID LEFT JOIN E_MATERIAL_WAREHOUSE_IN WI ON WID.WAREHOUSE_IN_ID = WI.ID
CD.CHECK_ID = #{checkId}
AND CD.MATERIAL_NAME LIKE #{materialNamePattern}
AND CD.SPECIFICATION_MODEL LIKE #{specificationModelPattern}
AND WI.WAREHOUSE_IN_NO LIKE #{warehouseInNoPattern}
AND WI.WAREHOUSE_IN_TITLE LIKE #{warehouseInTitlePattern}
AND WID.SUPPLIER_NAME LIKE #{supplierNamePattern}
AND CD.DIFFERENCE_TYPE = #{differenceType}
AND CD.CHECK_STATUS = #{checkStatus}
ORDER BY CD.MATERIAL_NAME, WI.WAREHOUSE_IN_NO

mapper.update:
BEGIN
UPDATE E_MATERIAL_STOCK_CHECK_DETAIL SET CHECK_QUANTITY = #{item.checkQuantity,jdbcType=NUMERIC}, DIFFERENCE_QUANTITY = #{item.differenceQuantity,jdbcType=NUMERIC}, DIFFERENCE_TYPE = #{item.differenceType,jdbcType=NUMERIC}, REMARK = #{item.remark,jdbcType=VARCHAR}, UPDATE_TIME = SYSDATE WHERE ID = #{item.id};
END;

mapper.insert:
INSERT INTO E_MATERIAL_STOCK_CHECK_DETAIL ( ID, CHECK_ID, MATERIAL_ID, MATERIAL_NAME, SPECIFICATION_MODEL, UNIT_CODE, UNIT_NAME, BOOK_QUANTITY, CHECK_QUANTITY, DIFFERENCE_QUANTITY, DIFFERENCE_TYPE, WAREHOUSE_IN_DETAIL_ID, CHECK_STATUS, CREATE_TIME ) SELECT SEQ_STOCK_CHECK_DETAIL_ID.NEXTVAL, #{checkId}, WID.MATERIAL_ID, WID.MATERIAL_NAME, WID.SPECIFICATION, WID.UNIT_CODE, WID.UNIT, WID.REMAINING_QUANTITY, NULL, 0, 0, WID.ID, 0, SYSDATE FROM E_MATERIAL_WAREHOUSE_IN_DETAIL WID INNER JOIN E_MATERIAL_WAREHOUSE_IN WI ON WID.WAREHOUSE_IN_ID = WI.ID WHERE WI.WAREHOUSE_ID = #{warehouseId} AND WI.ACCEPTANCE_STATUS = 1 AND WID.REMAINING_QUANTITY > 0
AND WID.MATERIAL_ID IN
#{materialId}
